# Test the escape sequence handling in _first_balanced_json

def _first_balanced_json(text: str) -> str | None:
    start = None
    for i, ch in enumerate(text):
        if ch in "{[":
            start = i
            break
    if start is None:
        return None
    open_ch = text[start]
    close_ch = "}" if open_ch == "{" else "]"
    depth = 0
    in_str = False
    escaped = False
    for i in range(start, len(text)):
        ch = text[i]
        if in_str:
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == '"':
                in_str = False
            continue
        if ch == '"':
            in_str = True
        elif ch == open_ch:
            depth += 1
        elif ch == close_ch:
            depth -= 1
            if depth == 0:
                return text[start:i + 1]
    return None

# Test cases
test_cases = [
    ('{"a": "b"}', '{"a": "b"}'),
    ('{"a": "\\""}', '{"a": "\\""}'),  # escaped quote
    ('{"a": "\\\\"}', '{"a": "\\\\"}'),  # escaped backslash
    ('{"a": "} in string"}', '{"a": "} in string"}'),  # brace in string
    ('text {"a": 1} more', '{"a": 1}'),  # leading prose
    ('[1, 2]', '[1, 2]'),  # array
    ('{"a": [1, 2]}', '{"a": [1, 2]}'),  # nested array
]

for text, expected in test_cases:
    result = _first_balanced_json(text)
    status = "✓" if result == expected else "✗"
    print(f"{status} {text!r} -> {result!r} (expected {expected!r})")
